function CameraFeed() {
  const [selected, setSelected] = React.useState('front_door');
  const [lastRefresh, setLastRefresh] = React.useState(new Date());

  const cameras = [
    { id: 'front_door', name: 'Front Door' },
    { id: 'backyard', name: 'Backyard' },
    { id: 'garage', name: 'Garage' },
    { id: 'living_room', name: 'Living Room' }
  ];

  const refresh = () => setLastRefresh(new Date());

  React.useEffect(() => {
    const interval = setInterval(refresh, 30000);
    return () => clearInterval(interval);
  }, []);

  const canvasRef = React.useRef(null);

  React.useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#0f172a';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = '#1e293b';
    for (let i = 0; i < 20; i++) {
      ctx.fillRect(Math.random() * canvas.width, Math.random() * canvas.height, 2, 2);
    }
    ctx.fillStyle = '#334155';
    ctx.font = '14px system-ui';
    ctx.textAlign = 'center';
    ctx.fillText(cameras.find(c => c.id === selected).name + ' Camera', canvas.width / 2, canvas.height / 2 - 10);
    ctx.fillText('Live Feed Simulation', canvas.width / 2, canvas.height / 2 + 10);
    ctx.fillStyle = '#ef4444';
    ctx.beginPath();
    ctx.arc(20, 20, 5, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = '#ef4444';
    ctx.font = '11px system-ui';
    ctx.textAlign = 'left';
    ctx.fillText('LIVE', 30, 24);
  }, [selected, lastRefresh]);

  return (
    <div style={{ fontFamily: 'system-ui', background: '#111827', color: '#f3f4f6', width: '100%', height: '100%', padding: 16, borderRadius: 8, boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
        <span style={{ fontSize: 14, fontWeight: 600, color: '#9ca3af' }}>Camera Feed</span>
        <button onClick={refresh} style={{ background: '#1f2937', color: '#f3f4f6', border: 'none', borderRadius: 6, padding: '4px 10px', fontSize: 12, cursor: 'pointer' }}>Refresh</button>
      </div>
      <div style={{ display: 'flex', gap: 6, marginBottom: 10 }}>
        {cameras.map(c => (
          <button key={c.id} onClick={() => setSelected(c.id)} style={{ flex: 1, padding: '6px 0', borderRadius: 6, border: 'none', background: selected === c.id ? '#3b82f6' : '#1f2937', color: '#fff', fontSize: 11, fontWeight: 600, cursor: 'pointer' }}>{c.name}</button>
        ))}
      </div>
      <canvas ref={canvasRef} width={320} height={200} style={{ width: '100%', flex: 1, borderRadius: 6, background: '#0f172a' }} />
      <div style={{ fontSize: 11, color: '#6b7280', marginTop: 6, textAlign: 'right' }}>Last refresh: {lastRefresh.toLocaleTimeString()}</div>
    </div>
  );
}
render(<CameraFeed/>);
